    info!("TEST START: test_calculate_throughput");
    let prev_bytes = 1_000_000_000u64;
    let curr_bytes = 1_125_000_000u64;
    let elapsed_ms = 1000;
    info!("INPUT: prev_bytes={}, curr_bytes={}, elapsed={}ms", prev_bytes, curr_bytes, elapsed_ms);
    let mbps = calculate_throughput_mbps(prev_bytes, curr_bytes, elapsed_ms);
    info!("RESULT: throughput = {} Mbps", mbps);
    assert!((mbps - 1000.0).abs() < 0.01);  // 125MB/s = 1000 Mbps
    info!("VERIFY: Expected 1000 Mbps, got {} Mbps", mbps);
    info!("TEST PASS: test_calculate_throughput");
}

#[test]
fn test_filter_physical_interfaces() {
    info!("TEST START: test_filter_physical_interfaces");
    let interfaces = vec!["eth0", "lo", "docker0", "veth1234", "ens192"];
    info!("INPUT: interfaces = {:?}", interfaces);
    let physical: Vec<_> = interfaces.iter().filter(|i| is_physical_interface(i)).collect();
    info!("RESULT: physical interfaces = {:?}", physical);
    assert_eq!(physical, vec![&"eth0", &"ens192"]);
    info!("VERIFY: Correctly filtered to eth0 and ens192");
    info!("TEST PASS: test_filter_physical_interfaces");
}
```

